package com.JavaOperator;

public class UnaryOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 5;
		int u = 10;
		
		int result = +a;
		System.out.println("+a : " + result);
		
		result = -u;
		System.out.println("-u : " + result);
		
		result = ++a;
		System.out.println("++a : " + result);
		
		result = --u;
		System.out.println("--u : " + result);
		
		boolean ok = false;
		System.out.println(ok);
		
	
		System.out.println(!ok);
		
		

	}

}
